mapper.select:
SELECT COUNT(DISTINCT f.HASH_ID) AS totalDetections, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, CASE WHEN COUNT(DISTINCT f.HASH_ID) > 0 THEN ROUND(SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) * 100.0 / COUNT(DISTINCT f.HASH_ID), 2) ELSE 0 END AS truePositiveRate, CASE WHEN COUNT(DISTINCT f.HASH_ID) > 0 THEN ROUND(SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) * 100.0 / COUNT(DISTINCT f.HASH_ID), 2) ELSE 0 END AS falsePositiveRate, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NULL THEN 1 ELSE 0 END) AS unprocessedCount FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}

SELECT s.DATA_TYPE AS datatype, COUNT(*) AS totalCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NULL THEN 1 ELSE 0 END) AS unprocessedCount, CASE WHEN COUNT(*) > 0 THEN ROUND(SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) ELSE 0 END AS truePositiveRate FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO LEFT JOIN pi_summary s ON f.TARGET_ID = s.TARGET_ID AND f.AP_NO = s.AP_NO AND f.HASH_ID = s.OBJECT_ID LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
GROUP BY s.DATA_TYPE ORDER BY totalCount DESC

SELECT DATE_FORMAT(f.REGDATE, '%Y-%m') AS month, COUNT(*) AS totalCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NULL THEN 1 ELSE 0 END) AS unprocessedCount FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID WHERE t.TARGET_USE = 'Y'
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
GROUP BY DATE_FORMAT(f.REGDATE, '%Y-%m') ORDER BY month ASC
